def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    len_bins = len(bins)
    for i in range(len_bins):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        base_score = 0
        if ratio > 3:
            base_score = 3000 + 100 * (ratio - 3) ** 4
        elif ratio > 2:
            base_score = 2000 + 75 * (ratio - 2) ** 3
        elif ratio > 1:
            base_score = 1000 + 30 * (ratio - 1) ** 2
        else:
            if ratio > 0.95:
                base_score = 90 * ratio + 20
            elif ratio > 0.8:
                base_score = 60 * ratio + 15
            elif ratio > 0.5:
                base_score = 25 * ratio + 10
            else:
                base_score = 7 * ratio
            if capacity < 3:
                base_score += 30
            elif capacity < 10:
                base_score += 15
            elif 50 < capacity < 150:
                base_score -= 10
            elif capacity > 300:
                base_score -= 25
        modifier = 1.0
        if i % 4 == 0:
            modifier += 0.2
            if ratio < 0.4:
                modifier += 0.1
            if capacity % 3 == 0:
                modifier -= 0.05
        elif i % 4 == 1:
            modifier -= 0.15
            if ratio > 1.7:
                modifier -= 0.1
            if capacity % 5 == 2:
                modifier += 0.07
        elif i % 4 == 2:
            modifier += 0.1
            if ratio > 0.9 and ratio < 1.1:
                modifier += 0.1
            if capacity % 2 == 1:
                modifier += 0.05
        else:
            modifier -= 0.05
            if capacity % 2 == 0:
                modifier += 0.04
            if ratio < 0.3:
                modifier += 0.08
        adjusted_score = base_score * modifier
        if i % 6 == 0:
            sum_diffs = 0
            count = 0
            for j in range(max(0, i-3), min(len_bins, i+4)):
                if j != i and bins[j] > 0:
                    diff = abs(item - bins[j])
                    if diff > capacity * 0.6:
                        adjusted_score *= 1.05
                    sum_diffs += diff
                    count += 1
            if count > 0:
                avg_diff = sum_diffs / count
                if avg_diff < capacity * 0.3:
                    adjusted_score *= 0.75
                elif avg_diff > capacity * 1.5:
                    adjusted_score *= 1.3
        if 2 <= i < len_bins - 2:
            window = bins[i-2:i+3]
            positive_bins = window[window > 0]
            if positive_bins.size > 0:
                median_capacity = np.median(positive_bins)
                if capacity < median_capacity * 0.5:
                    adjusted_score += 25
                elif capacity > median_capacity * 1.5:
                    adjusted_score -= 20
        priorities[i] = adjusted_score
    finite_priorities = priorities[np.isfinite(priorities)]
    fallback = 0 if finite_priorities.size == 0 else np.min(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = fallback + 200
    for i in range(len(priorities)):
        if priorities[i] < 15:
            increment = 15 * (item / (bins[i] + 1))
            if i % 2 == 0:
                increment *= 1.1
            else:
                increment *= 0.9
            priorities[i] += increment
    for i in range(len(priorities)):
        if 100 < priorities[i] < 300:
            for k in range(i+1, min(i+4, len(priorities))):
                if priorities[k] > priorities[i]:
                    priorities[i] += 5
                    break
    return priorities
